"use client";

import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { ArrowLeft, Download, Share2, TrendingUp, TrendingDown, Star, CheckCircle, AlertTriangle, XCircle } from "lucide-react";
import { getEvaluation, type EvaluationResult } from "@/lib/api";
import { useAuth } from "@/contexts/auth-context";
import { exportPdf } from "@/lib/exportPdf";

function getRecommendationColor(rec: string) {
  switch (rec) {
    case "Strong Hire": return "bg-green-500 text-white";
    case "Hire": return "bg-emerald-500 text-white";
    case "Consider": return "bg-yellow-500 text-white";
    case "No Hire": return "bg-red-500 text-white";
    default: return "bg-gray-500 text-white";
  }
}

function getRecommendationIcon(rec: string) {
  switch (rec) {
    case "Strong Hire": return <Star className="w-5 h-5" />;
    case "Hire": return <CheckCircle className="w-5 h-5" />;
    case "Consider": return <AlertTriangle className="w-5 h-5" />;
    case "No Hire": return <XCircle className="w-5 h-5" />;
    default: return null;
  }
}

function getScoreColor(score: number) {
  if (score >= 80) return "text-green-500";
  if (score >= 60) return "text-yellow-500";
  return "text-red-500";
}

export default function EvaluationPage() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const [evaluation, setEvaluation] = useState<EvaluationResult | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleShare = async () => {
    if (!evaluation) return;
    const text = `I scored ${evaluation.overallScore}/100 on my interview on InterVista!`;
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Ignored
    }
  };

  const handleDownload = () => {
    if (evaluation) {
      exportPdf(evaluation, evaluation.overallScore, "Candidate", "Role", "Company");
    }
  };

  const loadEvaluation = useCallback(async () => {
    if (!id) return;
    try {
      setLoading(true);
      setError(null);
      const data = await getEvaluation(id as string);

      if ('status' in data && data.status === 'evaluating') {
        // Continue loading state
        setLoading(true);
      } else {
        setEvaluation(data as EvaluationResult);
        setLoading(false);
      }
    } catch (err) {
      setError("Failed to load evaluation. Please try again later.");
      console.error(err);
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.push("/sign-in");
      return;
    }
    if (isAuthenticated && id) {
      loadEvaluation();
    }
  }, [authLoading, isAuthenticated, id, loadEvaluation, router]);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isAuthenticated && id && loading && !error) {
      interval = setInterval(async () => {
        try {
          const data = await getEvaluation(id as string);
          if (!('status' in data)) {
            setEvaluation(data as EvaluationResult);
            setLoading(false);
            clearInterval(interval);
          }
        } catch (err) {
          setError("Failed to load evaluation. Please try again later.");
          setLoading(false);
          clearInterval(interval);
        }
      }, 3000);
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isAuthenticated, id, loading, error]);

  if (authLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin mx-auto mb-4" />
          <p className="text-muted-foreground text-lg">AI is evaluating your answers...</p>
          <p className="text-sm text-muted-foreground mt-2">This may take a moment</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <div className="text-center">
          <p className="text-destructive mb-4">{error}</p>
          <Button onClick={() => router.push("/dashboard")}>
            Return to Dashboard
          </Button>
        </div>
      </div>
    );
  }

  if (!evaluation) return null;

  const skills = evaluation.skillsAssessment;
  const skillEntries = [
    { name: "Communication", value: skills.communication, icon: "≡ƒÆ¼" },
    { name: "Technical Knowledge", value: skills.technicalKnowledge, icon: "≡ƒºá" },
    { name: "Problem Solving", value: skills.problemSolving, icon: "≡ƒöº" },
    { name: "Confidence", value: skills.confidence, icon: "≡ƒÆ¬" },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5">
      <div className="container mx-auto px-4 py-8 max-w-5xl">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          <div className="flex items-center justify-between mb-8">
            <div>
              <h1 className="text-4xl font-bold mb-2">Interview Evaluation</h1>
              <p className="text-muted-foreground">
                Detailed analysis of your performance
              </p>
            </div>
            <div className="flex items-center space-x-3">
              <Button variant="outline" size="sm" onClick={handleShare}>
                <Share2 className="w-4 h-4 mr-2" />
                {copied ? "Copied!" : "Share"}
              </Button>
              <Button variant="outline" size="sm" onClick={handleDownload} disabled={!evaluation}>
                <Download className="w-4 h-4 mr-2" />
                Download
              </Button>
              <Button onClick={() => router.push("/dashboard")} size="sm">
                <ArrowLeft className="w-4 h-4 mr-2" />
                Dashboard
              </Button>
            </div>
          </div>

          {/* Top Row: Score + Recommendation + Summary */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
            {/* Overall Score */}
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.6, delay: 0.2 }}
            >
              <Card className="text-center h-full">
                <CardContent className="pt-8 pb-8">
                  <div className="relative inline-flex items-center justify-center mb-4">
                    <svg className="w-40 h-40 transform -rotate-90" viewBox="0 0 120 120">
                      <circle
                        cx="60" cy="60" r="50"
                        stroke="currentColor"
                        strokeWidth="8"
                        fill="none"
                        className="text-muted/20"
                      />
                      <circle
                        cx="60" cy="60" r="50"
                        stroke="currentColor"
                        strokeWidth="8"
                        fill="none"
                        strokeDasharray={`${(evaluation.overallScore / 100) * 314} 314`}
                        strokeLinecap="round"
                        className={getScoreColor(evaluation.overallScore)}
                      />
                    </svg>
                    <span className={`absolute text-4xl font-bold ${getScoreColor(evaluation.overallScore)}`}>
                      {evaluation.overallScore}
                    </span>
                  </div>
                  <div className={`inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold ${getRecommendationColor(evaluation.recommendation)}`}>
                    {getRecommendationIcon(evaluation.recommendation)}
                    {evaluation.recommendation}
                  </div>
                </CardContent>
              </Card>
            </motion.div>

            {/* Skills Assessment */}
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.6, delay: 0.3 }}
              className="lg:col-span-2"
            >
              <Card className="h-full">
                <CardHeader>
                  <CardTitle>Skills Assessment</CardTitle>
                </CardHeader>
                <CardContent className="space-y-5">
                  {skillEntries.map((skill) => (
                    <div key={skill.name}>
                      <div className="flex items-center justify-between mb-2">
                        <span className="text-sm font-medium flex items-center gap-2">
                          <span>{skill.icon}</span>
                          {skill.name}
                        </span>
                        <span className={`text-sm font-bold ${getScoreColor(skill.value)}`}>
                          {skill.value}/100
                        </span>
                      </div>
                      <Progress value={skill.value} className="h-3" />
                    </div>
                  ))}
                </CardContent>
              </Card>
            </motion.div>
          </div>

          {/* Summary */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.4 }}
            className="mb-8"
          >
            <Card>
              <CardHeader>
                <CardTitle>Summary</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-muted-foreground leading-relaxed">{evaluation.summary}</p>
              </CardContent>
            </Card>
          </motion.div>

          {/* Per-question Feedback */}
          <div className="space-y-6">
            <h2 className="text-2xl font-semibold">Question-by-Question Feedback</h2>
            {evaluation.feedback.map((fb, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.4, delay: 0.5 + index * 0.1 }}
              >
                <Card>
                  <CardHeader>
                    <div className="flex items-start justify-between">
                      <div className="flex items-start gap-3 flex-1">
                        <Badge variant="outline" className="shrink-0 mt-1">
                          Q{fb.questionIndex + 1}
                        </Badge>
                        <div className="space-y-1">
                          <CardTitle className="text-base leading-relaxed">{fb.question}</CardTitle>
                          <p className="text-sm text-muted-foreground italic">
                            &quot;{fb.answer}&quot;
                          </p>
                        </div>
                      </div>
                      <Badge className={`shrink-0 ml-4 ${fb.score >= 7 ? 'bg-green-500' : fb.score >= 5 ? 'bg-yellow-500' : 'bg-red-500'} text-white`}>
                        {fb.score}/10
                      </Badge>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <p className="text-sm text-muted-foreground">{fb.detailedFeedback}</p>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {/* Strengths */}
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-sm font-medium">
                          <TrendingUp className="w-4 h-4 text-green-500" />
                          Strengths
                        </div>
                        <ul className="space-y-1">
                          {fb.strengths.map((s, si) => (
                            <li key={si} className="text-sm text-muted-foreground flex items-start gap-2">
                              <span className="text-green-500 mt-0.5">Γ£ô</span>
                              {s}
                            </li>
                          ))}
                        </ul>
                      </div>

                      {/* Improvements */}
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-sm font-medium">
                          <TrendingDown className="w-4 h-4 text-yellow-500" />
                          Areas for Improvement
                        </div>
                        <ul className="space-y-1">
                          {fb.improvements.map((imp, ii) => (
                            <li key={ii} className="text-sm text-muted-foreground flex items-start gap-2">
                              <span className="text-yellow-500 mt-0.5">ΓåÆ</span>
                              {imp}
                            </li>
                          ))}
                        </ul>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </motion.div>
            ))}
          </div>

          {/* Bottom Actions */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1 }}
            className="flex justify-center gap-4 mt-12 mb-8"
          >
            <Button variant="outline" size="lg" onClick={() => router.push("/dashboard")}>
              Back to Dashboard
            </Button>
            <Button size="lg" onClick={() => router.push("/dashboard")}>
              Start New Interview
            </Button>
          </motion.div>
        </motion.div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Loader2, ArrowRight, CheckCircle, MessageSquare, Mic, Keyboard, Square, Play } from "lucide-react";
import { getSessionQuestions, submitAnswer, type Question } from "@/lib/api";
import { useAuth } from "@/contexts/auth-context";
import { useInterviewAudio } from "@/lib/useInterviewAudio";

export default function InterviewPage() {
  const params = useParams();
  const router = useRouter();
  const { isAuthenticated, isLoading: authLoading } = useAuth();
  const sessionId = params.id as string;

  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [currentAnswer, setCurrentAnswer] = useState("");
  const [error, setError] = useState("");
  const [inputMode, setInputMode] = useState<"record" | "type">("record");

  const {
    isRecording,
    audioBlob,
    audioUrl,
    transcript,
    startRecording,
    stopRecording,
    clearAudio,
  } = useInterviewAudio({ onSilenceDetected: () => {} });

  const loadQuestions = useCallback(async () => {
    try {
      setLoading(true);
      const data = await getSessionQuestions(sessionId);
      setQuestions(data);
    } catch (err: unknown) {
      console.error("Failed to load questions:", err);
      setError(err instanceof Error ? err.message : "Failed to load questions");
    } finally {
      setLoading(false);
    }
  }, [sessionId]);

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.push("/sign-in");
      return;
    }
    if (isAuthenticated && sessionId) {
      loadQuestions();
    }
  }, [authLoading, isAuthenticated, sessionId, loadQuestions, router]);

  async function handleSubmitAnswer() {
    const isAudioSubmission = inputMode === "record" && audioBlob;
    const isTextSubmission = inputMode === "type" && currentAnswer.trim();

    if (!isAudioSubmission && !isTextSubmission) return;

    const question = questions[currentQuestionIndex];

    try {
      setSubmitting(true);
      setError("");

      await submitAnswer({
        sessionId,
        questionId: question.id,
        questionIndex: currentQuestionIndex,
        text: isAudioSubmission ? (transcript || "") : currentAnswer.trim(),
        audioBlob: isAudioSubmission ? audioBlob : undefined,
      });

      // Move to next question or evaluation
      if (currentQuestionIndex < questions.length - 1) {
        setCurrentQuestionIndex((prev) => prev + 1);
        setCurrentAnswer("");
        clearAudio();
      } else {
        // All questions answered ΓÇö go to evaluation
        router.push(`/evaluation/${sessionId}`);
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Failed to submit answer");
    } finally {
      setSubmitting(false);
    }
  }

  if (authLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin mx-auto mb-4" />
          <p className="text-muted-foreground">Loading interview...</p>
        </div>
      </div>
    );
  }

  if (error && questions.length === 0) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <div className="text-center">
          <p className="text-destructive mb-4">{error}</p>
          <Button onClick={() => router.push("/dashboard")}>
            Return to Dashboard
          </Button>
        </div>
      </div>
    );
  }

  if (questions.length === 0) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <div className="text-center">
          <p className="text-muted-foreground mb-4">No questions found for this session</p>
          <Button onClick={() => router.push("/dashboard")}>
            Return to Dashboard
          </Button>
        </div>
      </div>
    );
  }

  const currentQuestion = questions[currentQuestionIndex];
  const progress = ((currentQuestionIndex + 1) / questions.length) * 100;
  const isLastQuestion = currentQuestionIndex === questions.length - 1;

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5">
      <div className="container mx-auto px-4 py-8 max-w-3xl">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-8"
        >
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <MessageSquare className="w-6 h-6 text-primary" />
              <h1 className="text-2xl font-bold">Interview Session</h1>
            </div>
            <Badge variant="outline" className="text-sm">
              Question {currentQuestionIndex + 1} of {questions.length}
            </Badge>
          </div>
          <Progress value={progress} className="h-2" />
        </motion.div>

        {/* Question Card */}
        <motion.div
          key={currentQuestionIndex}
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.3 }}
        >
          <Card className="mb-6 shadow-lg">
            <CardHeader>
              <div className="flex items-start gap-4">
                <div className="p-3 rounded-full bg-primary/10 text-primary shrink-0">
                  <span className="text-lg font-bold">{currentQuestionIndex + 1}</span>
                </div>
                <CardTitle className="text-xl leading-relaxed pt-1">
                  {currentQuestion.text}
                </CardTitle>
              </div>
            </CardHeader>
            <CardContent>
              {/* Input Mode Tabs */}
              <div className="flex gap-4 mb-6 border-b pb-2">
                <button
                  className={`flex items-center gap-2 pb-2 border-b-2 transition-colors ${inputMode === "record" ? "border-primary text-primary font-medium" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                  onClick={() => setInputMode("record")}
                >
                  <Mic className="w-4 h-4" /> Record Audio
                </button>
                <button
                  className={`flex items-center gap-2 pb-2 border-b-2 transition-colors ${inputMode === "type" ? "border-primary text-primary font-medium" : "border-transparent text-muted-foreground hover:text-foreground"}`}
                  onClick={() => setInputMode("type")}
                >
                  <Keyboard className="w-4 h-4" /> Type Answer
                </button>
              </div>

              <div className="space-y-4">
                {inputMode === "type" ? (
                  <div className="space-y-2">
                    <label htmlFor="answer" className="text-sm font-medium text-muted-foreground">
                      Your Answer
                    </label>
                    <textarea
                      id="answer"
                      className="w-full min-h-[200px] p-4 rounded-lg border border-input bg-background text-foreground resize-y focus:outline-none focus:ring-2 focus:ring-primary/50 focus:border-primary transition-colors"
                      placeholder="Type your answer here... Be as detailed as you can."
                      value={currentAnswer}
                      onChange={(e) => setCurrentAnswer(e.target.value)}
                      disabled={submitting}
                    />
                  </div>
                ) : (
                  <div className="space-y-6 flex flex-col items-center justify-center min-h-[200px] border rounded-lg bg-muted/20 p-8">
                    {!audioBlob && !isRecording && (
                      <div className="text-center">
                        <button
                          onClick={startRecording}
                          disabled={submitting}
                          className="w-20 h-20 bg-red-500 hover:bg-red-600 rounded-full flex items-center justify-center text-white shadow-lg transition-transform hover:scale-105"
                        >
                          <Mic className="w-8 h-8" />
                        </button>
                        <p className="mt-4 text-sm text-muted-foreground font-medium">Click to start recording</p>
                      </div>
                    )}

                    {isRecording && (
                      <div className="text-center w-full">
                        <div className="flex justify-center mb-6">
                            <div className="flex gap-1 items-center h-12">
                                {[1,2,3,4,5].map(i => (
                                    <motion.div 
                                      key={i}
                                      animate={{ height: ["20%", "100%", "20%"] }}
                                      transition={{ duration: 0.8, repeat: Infinity, delay: i * 0.1 }}
                                      className="w-2 bg-red-500 rounded-full mx-1"
                                    />
                                ))}
                            </div>
                        </div>
                        <p className="mb-4 font-medium text-red-500 animate-pulse">Recording...</p>
                        <Button variant="destructive" onClick={stopRecording}>
                          <Square className="w-4 h-4 mr-2" /> Stop Recording
                        </Button>

                        {transcript && (
                          <div className="mt-6 p-4 rounded-lg bg-background text-left text-sm max-h-32 overflow-y-auto border">
                            <p className="text-muted-foreground mb-1 font-medium">Live Transcript:</p>
                            <p>{transcript}</p>
                          </div>
                        )}
                      </div>
                    )}

                    {audioBlob && audioUrl && !isRecording && (
                      <div className="w-full space-y-4">
                        <div className="flex items-center justify-between border rounded-full p-2 bg-background">
                            <audio src={audioUrl} controls className="h-10 w-full ml-2 mr-4" />
                            <Button variant="ghost" size="icon" onClick={clearAudio} title="Discard and re-record" className="shrink-0 flex text-muted-foreground hover:text-destructive">
                                <Square className="w-4 h-4" /> {/* Or trash icon */}
                            </Button>
                        </div>

                        {transcript && (
                          <div className="p-4 rounded-lg bg-background text-left text-sm max-h-32 overflow-y-auto border">
                            <p className="text-muted-foreground mb-1 font-medium">Transcript:</p>
                            <p>{transcript}</p>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                )}

                {error && (
                  <div className="p-3 text-sm text-destructive bg-destructive/10 rounded-md">
                    {error}
                  </div>
                )}

                <div className="flex items-center justify-between pt-2">
                  <p className="text-sm text-muted-foreground">
                    {inputMode === "type" 
                      ? (currentAnswer.length > 0 ? `${currentAnswer.split(/\s+/).filter(Boolean).length} words` : "Start typing your answer")
                      : (audioBlob ? "Audio recorded successfully" : "Speak to answer")
                    }
                  </p>
                  <Button
                    onClick={handleSubmitAnswer}
                    disabled={submitting || (inputMode === "type" ? !currentAnswer.trim() : !audioBlob)}
                    size="lg"
                    className="min-w-[160px]"
                  >
                    {submitting ? (
                      <>
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        {inputMode === 'record' ? 'Transcribing...' : 'Submitting...'}
                      </>
                    ) : isLastQuestion ? (
                      <>
                        <CheckCircle className="w-4 h-4 mr-2" />
                        Finish Interview
                      </>
                    ) : (
                      <>
                        Next Question
                        <ArrowRight className="w-4 h-4 ml-2" />
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        </motion.div>

        {/* Question Navigator Dots */}
        <div className="flex justify-center gap-2 mt-6">
          {questions.map((_, i) => (
            <div
              key={i}
              className={`w-3 h-3 rounded-full transition-colors ${
                i < currentQuestionIndex
                  ? "bg-green-500"
                  : i === currentQuestionIndex
                  ? "bg-primary"
                  : "bg-muted"
              }`}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { EnhancedNavbar } from "@/components/layout/enhanced-navbar";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { Bell, Lock, Globe, Trash2, LogOut, Loader2 } from "lucide-react";
import { useAuth } from "@/contexts/auth-context";
import * as api from "@/lib/api";
import toast from "react-hot-toast";
import { useEffect, useRef } from "react";

export default function SettingsPage() {
  const { signOut } = useAuth();
  const [loading, setLoading] = useState(true);
  const [notifications, setNotifications] = useState({
    email: true,
    push: false,
    sms: false,
  });
  const [language, setLanguage] = useState("English");
  const [timezone, setTimezone] = useState("UTC-8 (Pacific Time)");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [passwordLoading, setPasswordLoading] = useState(false);
  const [deleteLoading, setDeleteLoading] = useState(false);


  useEffect(() => {
    async function load() {
      try {
        const profile = await api.getProfile();
        if (profile.preferences) {
          setNotifications({
            email: profile.preferences.emailNotifications,
            push: profile.preferences.pushNotifications,
            sms: false, // Not persisted in backend schema currently
          });
          setLanguage(profile.preferences.language);
          setTimezone(profile.preferences.timezone);
        }
      } catch (err) {
        console.error("Failed to load profile", err);
      } finally {
        setLoading(false);
      }
    }
    load();
  }, []);

  const initialRender = useRef(true);
  useEffect(() => {
    if (initialRender.current) {
      initialRender.current = false;
      return;
    }
    const timeout = setTimeout(async () => {
      try {
        await api.updatePreferences({
          emailNotifications: notifications.email,
          pushNotifications: notifications.push,
          language,
          timezone,
        });
      } catch (err) {
        console.error("Failed to save preferences", err);
      }
    }, 500);
    return () => clearTimeout(timeout);
  }, [notifications, language, timezone]);

  const handlePasswordChange = async () => {
    if (newPassword !== confirmPassword) {
      toast.error("New passwords don't match");
      return;
    }
    if (newPassword.length < 8) {
      toast.error("Password must be at least 8 characters");
      return;
    }

    setPasswordLoading(true);
    try {
      await api.changePassword(currentPassword, newPassword);
      toast.success("Password changed successfully");
      setCurrentPassword("");
      setNewPassword("");
      setConfirmPassword("");
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : String(err));
    } finally {
      setPasswordLoading(false);
    }
  };

  const handleDeleteAccount = async () => {
    if (!confirm("Are you sure you want to permanently delete your account? This action cannot be undone.")) {
      return;
    }
    setDeleteLoading(true);
    try {
      await api.deleteAccount();
      toast.success("Account deleted");
      await signOut();
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : String(err));
    } finally {
      setDeleteLoading(false);
    }
  };

  return (
    <main className="min-h-screen bg-background">
      <EnhancedNavbar />

      <div className="pt-24 pb-16">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="max-w-4xl mx-auto"
          >
            <h1 className="text-4xl font-bold mb-8">Settings</h1>

            <div className="space-y-6">
              {/* Notifications */}
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center">
                    <Bell className="w-5 h-5 mr-2" />
                    Notifications
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <Label htmlFor="email-notif">Email Notifications</Label>
                      <p className="text-sm text-muted-foreground">
                        Receive updates about your interviews via email
                      </p>
                    </div>
                    <Switch
                      id="email-notif"
                      checked={notifications.email}
                      onCheckedChange={(checked) =>
                        setNotifications({ ...notifications, email: checked })
                      }
                    />
                  </div>

                  <Separator />

                  <div className="flex items-center justify-between">
                    <div>
                      <Label htmlFor="push-notif">Push Notifications</Label>
                      <p className="text-sm text-muted-foreground">
                        Get notified about interview reminders
                      </p>
                    </div>
                    <Switch
                      id="push-notif"
                      checked={notifications.push}
                      onCheckedChange={(checked) =>
                        setNotifications({ ...notifications, push: checked })
                      }
                    />
                  </div>

                  <Separator />

                  <div className="flex items-center justify-between">
                    <div>
                      <Label htmlFor="sms-notif">SMS Notifications</Label>
                      <p className="text-sm text-muted-foreground">
                        Receive text messages for important updates
                      </p>
                    </div>
                    <Switch
                      id="sms-notif"
                      checked={notifications.sms}
                      onCheckedChange={(checked) =>
                        setNotifications({ ...notifications, sms: checked })
                      }
                    />
                  </div>
                </CardContent>
              </Card>

              {/* Security */}
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center">
                    <Lock className="w-5 h-5 mr-2" />
                    Security
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div>
                    <Label htmlFor="current-password">Current Password</Label>
                    <Input
                      id="current-password"
                      type="password"
                      placeholder="Enter current password"
                      className="mt-2"
                      value={currentPassword}
                      onChange={(e) => setCurrentPassword(e.target.value)}
                    />
                  </div>

                  <div>
                    <Label htmlFor="new-password">New Password</Label>
                    <Input
                      id="new-password"
                      type="password"
                      placeholder="Enter new password"
                      className="mt-2"
                      value={newPassword}
                      onChange={(e) => setNewPassword(e.target.value)}
                    />
                  </div>

                  <div>
                    <Label htmlFor="confirm-password">Confirm New Password</Label>
                    <Input
                      id="confirm-password"
                      type="password"
                      placeholder="Confirm new password"
                      className="mt-2"
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                    />
                  </div>

                  <Button onClick={handlePasswordChange} disabled={passwordLoading}>
                    {passwordLoading ? (
                      <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Updating...</>
                    ) : (
                      "Update Password"
                    )}
                  </Button>
                </CardContent>
              </Card>

              {/* Preferences */}
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center">
                    <Globe className="w-5 h-5 mr-2" />
                    Preferences
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div>
                    <Label htmlFor="language">Language</Label>
                    <select
                      id="language"
                      value={language}
                      onChange={(e) => setLanguage(e.target.value)}
                      className="w-full mt-2 px-3 py-2 border border-input rounded-md bg-background"
                    >
                      <option value="English">English</option>
                      <option value="Spanish">Spanish</option>
                      <option value="French">French</option>
                      <option value="German">German</option>
                    </select>
                  </div>

                  <div>
                    <Label htmlFor="timezone">Timezone</Label>
                    <select
                      id="timezone"
                      value={timezone}
                      onChange={(e) => setTimezone(e.target.value)}
                      className="w-full mt-2 px-3 py-2 border border-input rounded-md bg-background"
                    >
                      <option value="UTC-8 (Pacific Time)">UTC-8 (Pacific Time)</option>
                      <option value="UTC-5 (Eastern Time)">UTC-5 (Eastern Time)</option>
                      <option value="UTC+0 (GMT)">UTC+0 (GMT)</option>
                      <option value="UTC+1 (CET)">UTC+1 (CET)</option>
                    </select>
                  </div>
                </CardContent>
              </Card>

              {/* Danger Zone */}
              <Card className="border-destructive">
                <CardHeader>
                  <CardTitle className="flex items-center text-destructive">
                    <Trash2 className="w-5 h-5 mr-2" />
                    Danger Zone
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <Label>Sign Out</Label>
                      <p className="text-sm text-muted-foreground">
                        Sign out of your account on this device
                      </p>
                    </div>
                    <Button variant="outline" onClick={() => signOut()}>
                      <LogOut className="w-4 h-4 mr-2" />
                      Sign Out
                    </Button>
                  </div>

                  <Separator />

                  <div className="flex items-center justify-between">
                    <div>
                      <Label>Delete Account</Label>
                      <p className="text-sm text-muted-foreground">
                        Permanently delete your account and all data
                      </p>
                    </div>
                    <Button variant="destructive" onClick={handleDeleteAccount} disabled={deleteLoading}>
                      {deleteLoading ? (
                        <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Deleting...</>
                      ) : (
                        <><Trash2 className="w-4 h-4 mr-2" /> Delete Account</>
                      )}
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </div>
          </motion.div>
        </div>
      </div>
    </main>
  );
}

